using System.Collections;
using UnityEngine;

// Ataques aquáticos (Etapas 2.1 e 3.2). Apenas afectam o alvo se este estiver
// em água (WaterDetector — ver EnemyAttackController.IsTargetInWater/Submerged).
//
// Exemplos do GDD como combinações reutilizáveis (Etapa 3.2):
// - Mina flutuante:        Nada (sem Mergulha) + Attack_ExplodeOnContact.
// - Boia com rede:         Nada (superfície) + Attack_Net (usableInWater, waterPosition = SoSuperficie).
// - Rede temporária:       Attack_Net (trapDuration curto) em qualquer máquina aquática.
// - Motor com corrente:    Estático/Flutuante + Attack_WaterCurrent (mode = PuxarParaInimigo).
// - Turbina (empurra para hazards): Attack_WaterCurrent (mode = DirecaoFixa apontada ao hazard, ou EmpurrarDoInimigo).
// - Drone submarino:       Mergulha + EnemyMovement Mergulhador + Attack_UnderwaterDash e/ou
//                          Attack_ProjectileStraight (usableInWater, waterPosition = SoSubmerso).
// - Cabo eléctrico:        Estático + Attack_ElectrifyWater.
// - Gancho que puxa para baixo: Attack_HookPullDown (afogar o player).

/// <summary>Modo de direcção da corrente de água (Attack_WaterCurrent — Etapa 3.2).</summary>
public enum WaterCurrentMode
{
    /// <summary>Empurra o player numa direcção fixa ("currentDirection") — ex: turbina que empurra contra hazards.</summary>
    DirecaoFixa,

    /// <summary>Empurra o player para longe do inimigo.</summary>
    EmpurrarDoInimigo,

    /// <summary>Puxa o player em direcção ao inimigo — ex: motor que cria corrente de sucção.</summary>
    PuxarParaInimigo
}

/// <summary>Corrente na água: empurra/puxa o player (conforme "mode") enquanto este estiver em água, durante "duration" segundos.</summary>
[System.Serializable]
public class Attack_WaterCurrent : EnemyAttack
{
    [Header("Corrente na Água")]
    [Tooltip("Direcção fixa / empurrar do inimigo / puxar para o inimigo (Etapa 3.2).")]
    public WaterCurrentMode mode = WaterCurrentMode.DirecaoFixa;

    [Tooltip("Direcção da corrente (usada apenas com mode = DirecaoFixa).")]
    public Vector2 currentDirection = Vector2.left;

    public float currentForce = 4f;
    public float duration = 1.5f;

    public Attack_WaterCurrent()
    {
        attackName = "Corrente";
        range = 5f;
        damage = 0;
        usableOnGround = false;
        usableInWater = true;
        prepTime = 0.3f;
        recoveryTime = 0.4f;
        cooldown = 2.5f;
    }

    public override IEnumerator Execute(EnemyAttackController ctx)
    {
        float elapsed = 0f;

        while (elapsed < duration)
        {
            if (ctx.IsTargetInWater())
            {
                Vector2 dir;
                switch (mode)
                {
                    case WaterCurrentMode.EmpurrarDoInimigo: dir = ctx.DirectionToTarget(); break;
                    case WaterCurrentMode.PuxarParaInimigo: dir = -ctx.DirectionToTarget(); break;
                    default: dir = currentDirection; break;
                }

                ctx.PushPlayer(currentForce, dir);
            }

            elapsed += Time.deltaTime;
            yield return null;
        }

        if (damage > 0 && ctx.IsTargetInWater())
            ctx.DamagePlayer(damage, knockbackForce);
    }
}

/// <summary>Electrifica a água: causa dano periódico a quem estiver em água dentro de "electrifyRadius", durante "duration" segundos.</summary>
[System.Serializable]
public class Attack_ElectrifyWater : EnemyAttack
{
    [Header("Electrificar Água")]
    public float electrifyRadius = 5f;
    public float duration = 1f;
    public float tickInterval = 0.25f;

    public Attack_ElectrifyWater()
    {
        attackName = "Electrificar Água";
        range = 6f;
        usableOnGround = false;
        usableInWater = true;
        prepTime = 0.5f;
        recoveryTime = 0.6f;
        cooldown = 4f;
    }

    public override IEnumerator Execute(EnemyAttackController ctx)
    {
        float elapsed = 0f;

        while (elapsed < duration)
        {
            if (ctx.IsTargetInWater() && ctx.IsTargetWithin(ctx.transform.position, electrifyRadius))
                ctx.DamagePlayer(damage, knockbackForce);

            yield return new WaitForSeconds(tickInterval);
            elapsed += tickInterval;
        }
    }
}

/// <summary>
/// Mina (explosão por proximidade — Etapa 3.2): quando o alvo se aproxima
/// (CanUse com "range" pequeno), o telegraph (prepTime = "beep") corre e a mina
/// explode, causando dano em área e destruindo-se a si própria
/// ("destroySelf"). Combinar com EnemyWaterConfig.canSwim (sem Mergulha) para a
/// "mina flutuante" do GDD; também funciona fora de água (mina terrestre).
/// </summary>
[System.Serializable]
public class Attack_ExplodeOnContact : EnemyAttack
{
    [Header("Mina (Explosão por Proximidade)")]
    [Tooltip("Raio da explosão (dano em área a partir do centro da mina).")]
    public float explosionRadius = 2f;

    [Tooltip("A mina destrói-se ao explodir (passa por EnemyHealth.Kill — respeita 'canOnlyBeDeactivated').")]
    public bool destroySelf = true;

    public Attack_ExplodeOnContact()
    {
        attackName = "Mina";
        range = 1.5f; // distância de "armar" a explosão
        damage = 2;
        knockbackForce = 8f;
        usableOnGround = false;
        usableInWater = true;
        prepTime = 0.4f; // "beep" de aviso
        recoveryTime = 0.1f;
        cooldown = 1f;
    }

    public override IEnumerator Execute(EnemyAttackController ctx)
    {
        if (ctx.IsTargetWithin(ctx.transform.position, explosionRadius))
            ctx.DamagePlayer(damage, knockbackForce);

        if (destroySelf)
        {
            var health = ctx.Controller.GetEnemyComponent<EnemyHealth>();
            if (health != null) health.Kill();
            else ctx.Controller.SetState(EnemyState.Morto);
        }

        yield break;
    }
}

/// <summary>
/// Gancho que puxa o player para baixo (Etapa 3.2 — afogar): durante
/// "duration", puxa o alvo para o fundo enquanto este estiver em água.
/// </summary>
[System.Serializable]
public class Attack_HookPullDown : EnemyAttack
{
    [Header("Gancho (Puxar Para Baixo)")]
    [Tooltip("Velocidade com que o player é puxado para baixo.")]
    public float pullSpeed = 5f;

    [Tooltip("Duração do puxão, em segundos.")]
    public float duration = 1f;

    [Tooltip("Só puxa enquanto o alvo estiver em água (desligar para ganchos que apanham o player à beira de água).")]
    public bool onlyWhileTargetInWater = true;

    public Attack_HookPullDown()
    {
        attackName = "Gancho Para Baixo";
        range = 4f;
        damage = 0;
        requiresLineOfSight = true;
        usableOnGround = false;
        usableInWater = true;
        prepTime = 0.4f;
        recoveryTime = 0.6f;
        cooldown = 3.5f;
    }

    public override IEnumerator Execute(EnemyAttackController ctx)
    {
        float elapsed = 0f;

        while (elapsed < duration)
        {
            if (ctx.Target == null) yield break;

            if (!onlyWhileTargetInWater || ctx.IsTargetInWater())
                ctx.PullPlayer(pullSpeed, Vector2.down);

            elapsed += Time.deltaTime;
            yield return null;
        }

        if (damage > 0 && (!onlyWhileTargetInWater || ctx.IsTargetInWater()))
            ctx.DamagePlayer(damage, knockbackForce);
    }
}

/// <summary>
/// Investida aquática (Etapa 3.2 — ex: drone submarino): nada em direcção ao
/// alvo a "attackSwimSpeed" durante "dashDuration", causando dano ao tocar.
/// </summary>
[System.Serializable]
public class Attack_UnderwaterDash : EnemyAttack
{
    [Header("Investida Aquática")]
    public float dashDuration = 0.5f;

    [Tooltip("Distância ao alvo considerada 'acertou' durante a investida.")]
    public float hitRadius = 0.7f;

    public Attack_UnderwaterDash()
    {
        attackName = "Investida Aquática";
        range = 5f;
        minRange = 1f;
        usableOnGround = false;
        usableInWater = true;
        waterPosition = WaterAttackPosition.SoSubmerso;
        attackSwimSpeed = 8f;
        prepTime = 0.3f;
        recoveryTime = 0.4f;
        cooldown = 2f;
    }

    public override IEnumerator Execute(EnemyAttackController ctx)
    {
        bool hit = false;
        float elapsed = 0f;

        while (elapsed < dashDuration)
        {
            ctx.SwimTowardsTarget(attackSwimSpeed > 0f ? attackSwimSpeed : 8f);

            if (!hit && ctx.IsTargetWithin(ctx.transform.position, hitRadius))
            {
                hit = true;
                ctx.DamagePlayer(damage, knockbackForce);
            }

            elapsed += Time.deltaTime;
            yield return null;
        }

        if (ctx.Rb != null) ctx.Rb.velocity = Vector2.zero;
    }
}
